// ── LENS PREVIEW SYSTEM ──────────────────────────────────────────────────
const LP_DISTS=[10,20,30,40];
const LP_LABELS=['10ft','20ft','30ft','40ft'];
const LP_SUBS=['close range','mid range','far range','maximum range'];
const LP_IMG_SMALL='data:image/jpeg;base64,';
const LP_IMG_LARGE='data:image/jpeg;base64,';
