let lpHideTimer=null;
let lpCurrentSku=null;
const lpCanvasCache={};  // key=sku+size, value=dataURL

function drawLensPanel(canvas,distFt){
  const W=canvas.width,H=canvas.height;
  const ctx=canvas.getContext('2d');
  const detail=Math.max(0,Math.min(1,1-(distFt-8)/38));

  // Sky
  const sky=ctx.createLinearGradient(0,0,0,H*0.4);
  sky.addColorStop(0,'#4a7a9a');sky.addColorStop(1,'#80aabf');
  ctx.fillStyle=sky;ctx.fillRect(0,0,W,H*0.4);
  // Clouds
  ctx.fillStyle='rgba(255,255,255,0.5)';
  [[0.15,0.08,0.1,0.04],[0.55,0.06,0.14,0.035],[0.8,0.1,0.09,0.03]].forEach(([rx,ry,rw,rh])=>{
    ctx.beginPath();ctx.ellipse(W*rx,H*ry,W*rw,H*rh,0,0,Math.PI*2);ctx.fill();
  });
  // Ground
  const gnd=ctx.createLinearGradient(0,H*0.4,0,H);
  gnd.addColorStop(0,'#7a7870');gnd.addColorStop(1,'#58584f');
  ctx.fillStyle=gnd;ctx.fillRect(0,H*0.4,W,H*0.6);
  // Tarmac lines
  ctx.strokeStyle='rgba(0,0,0,0.1)';ctx.lineWidth=0.5;
  for(let i=0;i<8;i++){const y=H*0.4+i*(H*0.6/7);ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(W,y);ctx.stroke();}
  // Road marking
  ctx.strokeStyle='rgba(255,255,255,0.28)';ctx.lineWidth=1.2;ctx.setLineDash([H*0.04,H*0.03]);
  ctx.beginPath();ctx.moveTo(W*0.5,H*0.4);ctx.lineTo(W*0.5,H);ctx.stroke();ctx.setLineDash([]);
  // Building L
  ctx.fillStyle='#c0bcb4';ctx.fillRect(0,H*0.08,W*0.38,H*0.32);
  ctx.fillStyle='#787470';ctx.fillRect(W*0.06,H*0.2,W*0.18,H*0.2);
  ctx.strokeStyle='rgba(0,0,0,0.15)';ctx.lineWidth=0.5;
  for(let i=0;i<5;i++)ctx.strokeRect(W*0.06,H*0.2+i*(H*0.2/5),W*0.18,H*0.2/5);
  // Building R
  ctx.fillStyle='#b0acaa';ctx.fillRect(W*0.6,H*0.1,W*0.4,H*0.3);
  ctx.fillStyle='#888480';ctx.fillRect(W*0.65,H*0.22,W*0.15,H*0.18);
  for(let i=0;i<5;i++)ctx.strokeRect(W*0.65,H*0.22+i*(H*0.18/5),W*0.15,H*0.18/5);
  // Trees
  [[0.42,0.24,0.055],[0.52,0.22,0.065],[0.58,0.25,0.045]].forEach(([rx,ry,rr])=>{
    ctx.fillStyle='#3a5c2a';ctx.beginPath();ctx.arc(W*rx,H*ry,W*rr,0,Math.PI*2);ctx.fill();
    ctx.fillRect(W*rx-W*0.006,H*ry,W*0.012,H*0.12);
  });
  // Parked cars
  ctx.fillStyle='#2a2a30';ctx.fillRect(W*0.72,H*0.44,W*0.22,H*0.07);
  ctx.fillStyle='#1a202a';ctx.fillRect(W*0.05,H*0.5,W*0.18,H*0.07);

  // ── PERSON ──
  const scaleFactor=1/(distFt/10);
  const pH=H*Math.min(0.78,0.38*scaleFactor+0.1);
  const pW=pH*0.3;
  const px=W*0.5;
  const groundY=H*(0.4+0.35*(1-1/(distFt/8+1)));
  const feetY=Math.min(groundY+pH*0.05,H*0.94);
  const headTop=feetY-pH;
  const headCY=headTop+pH*0.1;
  const headR=pH*0.09;
  const bodyTop=headTop+pH*0.18;
  const bodyBot=headTop+pH*0.62;
  // Shadow
  ctx.fillStyle='rgba(0,0,0,0.22)';ctx.beginPath();ctx.ellipse(px,feetY+1,pW*0.6,pH*0.02,0,0,Math.PI*2);ctx.fill();
  // Legs
  ctx.fillStyle='#111115';
  ctx.beginPath();ctx.moveTo(px-pW*0.04,bodyBot);ctx.lineTo(px-pW*0.36,feetY);ctx.lineTo(px-pW*0.17,feetY);ctx.lineTo(px-pW*0.02,bodyBot);ctx.closePath();ctx.fill();
  ctx.beginPath();ctx.moveTo(px+pW*0.04,bodyBot);ctx.lineTo(px+pW*0.36,feetY);ctx.lineTo(px+pW*0.17,feetY);ctx.lineTo(px+pW*0.02,bodyBot);ctx.closePath();ctx.fill();
  // Shoes
  ctx.fillStyle='#0a0a0a';
  ctx.beginPath();ctx.ellipse(px-pW*0.24,feetY,pW*0.14,pH*0.018,0,0,Math.PI*2);ctx.fill();
  ctx.beginPath();ctx.ellipse(px+pW*0.24,feetY,pW*0.14,pH*0.018,0,0,Math.PI*2);ctx.fill();
  // Body
  ctx.fillStyle='#141418';
  ctx.beginPath();ctx.moveTo(px-pW*0.36,bodyTop+pH*0.04);ctx.lineTo(px-pW*0.4,bodyBot);ctx.lineTo(px+pW*0.4,bodyBot);ctx.lineTo(px+pW*0.36,bodyTop+pH*0.04);ctx.closePath();ctx.fill();
  // Arms
  ctx.fillStyle='#111114';
  ctx.beginPath();ctx.moveTo(px-pW*0.34,bodyTop+pH*0.06);ctx.lineTo(px-pW*0.58,bodyBot-pH*0.05);ctx.lineTo(px-pW*0.46,bodyBot-pH*0.03);ctx.lineTo(px-pW*0.26,bodyTop+pH*0.08);ctx.closePath();ctx.fill();
  ctx.beginPath();ctx.moveTo(px+pW*0.34,bodyTop+pH*0.06);ctx.lineTo(px+pW*0.58,bodyBot-pH*0.05);ctx.lineTo(px+pW*0.46,bodyBot-pH*0.03);ctx.lineTo(px+pW*0.26,bodyTop+pH*0.08);ctx.closePath();ctx.fill();
  // Sign
  if(distFt<=30){
    const sw=pW*0.85,sh=Math.max(3,pH*0.055),sy=bodyTop+pH*0.38;
    ctx.fillStyle='#f2f0ec';ctx.fillRect(px-sw/2,sy,sw,sh);
    ctx.strokeStyle='#bbb';ctx.lineWidth=0.4;ctx.strokeRect(px-sw/2,sy,sw,sh);
    if(detail>0.35&&sh>5){ctx.fillStyle='#111';ctx.font=`bold ${Math.max(5,sh*0.7)}px monospace`;ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('DDS 23 56',px,sy+sh/2);}
  }
  // Neck
  ctx.fillStyle='#c8a080';ctx.beginPath();ctx.ellipse(px,bodyTop+pH*0.01,pW*0.07,pH*0.035,0,0,Math.PI*2);ctx.fill();
  // Head
  ctx.fillStyle='#c8a078';ctx.beginPath();ctx.ellipse(px,headCY,headR*0.72,headR,0,0,Math.PI*2);ctx.fill();
  // Hair
  ctx.fillStyle='#100c06';
  ctx.beginPath();ctx.ellipse(px,headCY-headR*0.35,headR*0.72,headR*0.58,0,Math.PI,0);ctx.fill();
  ctx.beginPath();ctx.ellipse(px+headR*0.55,headCY+headR*0.25,headR*0.2,headR*0.55,0.4,0,Math.PI*2);ctx.fill();
  // Face
  if(detail>0.45){
    const fa=Math.min(1,(detail-0.45)/0.55);
    ctx.fillStyle=`rgba(35,28,20,${fa*0.85})`;
    ctx.beginPath();ctx.ellipse(px-headR*0.3,headCY-headR*0.06,headR*0.1,headR*0.075,0,0,Math.PI*2);ctx.fill();
    ctx.beginPath();ctx.ellipse(px+headR*0.3,headCY-headR*0.06,headR*0.1,headR*0.075,0,0,Math.PI*2);ctx.fill();
    ctx.strokeStyle=`rgba(150,80,70,${fa*0.65})`;ctx.lineWidth=headR*0.065;
    ctx.beginPath();ctx.arc(px,headCY+headR*0.28,headR*0.2,0.2,Math.PI-0.2);ctx.stroke();
  }
  // Noise at distance
  if(detail<0.55){const nm=(1-detail)*0.045;for(let n=0;n<80;n++){ctx.fillStyle=`rgba(180,185,175,${nm*Math.random()})`;ctx.fillRect(Math.random()*W,Math.random()*H,Math.random()*1.8,Math.random()*1.8);}}
  // Vignette
  const vig=ctx.createRadialGradient(W/2,H/2,H*0.2,W/2,H/2,H*0.7);
  vig.addColorStop(0,'rgba(0,0,0,0)');vig.addColorStop(1,'rgba(0,0,0,0.5)');
  ctx.fillStyle=vig;ctx.fillRect(0,0,W,H);
}

function buildLensPreview(){
  const quad=document.getElementById('lpQuad');
  quad.innerHTML='';
  quad.style.display='block';
  const img=document.createElement('img');
  img.src=LP_IMG_LARGE;
  img.style.cssText='width:100%;border-radius:5px;display:block';
  quad.appendChild(img);
}

function buildLensExpand(){
  const quad=document.getElementById('leQuad');
  quad.innerHTML='';
  quad.style.cssText='width:88vw;max-width:920px;height:auto';
  const img=document.createElement('img');
  img.src=LP_IMG_LARGE;
  img.style.cssText='width:100%;border-radius:7px;display:block';
  quad.appendChild(img);
}

function openLensExpand(e){
  if(e){e.stopPropagation();e.preventDefault();}
  hideLensPreview();
  const overlay=document.getElementById('lensExpand');
  overlay.style.display='flex';
  overlay.classList.add('active');
}
function closeLensExpand(e,force){
  if(force||!e||e.target===document.getElementById('lensExpand')||e.target===document.getElementById('lpExpandImg')){
    const overlay=document.getElementById('lensExpand');
    overlay.classList.remove('active');
    overlay.style.display='';
  }
}

function showLensPreview(x,y,specs){
  const lp=document.getElementById('lensPreview');
  if(!lp)return;
  const lbl=specs?`${specs.lensLabel||'2.8mm'} \u00b7 ${specs.mp||4}MP \u00b7 ${specs.fovDeg||107}\u00b0`:'2.8mm \u00b7 4MP \u00b7 107\u00b0';
  document.getElementById('lpBadge').textContent=lbl;
  document.getElementById('leTitle').textContent=`${lbl} \u00b7 Camera height 15ft \u00b7 Click outside to close`;
  // Static image — no build needed
  const pw=216,ph=200;
  // Position well clear of the camera so right-click still works
  let lx=x+30,ly=y-ph/2;
  if(lx+pw>window.innerWidth-8)lx=x-pw-30;
  if(ly<8)ly=8;
  if(ly+ph>window.innerHeight-8)ly=window.innerHeight-ph-8;
  lp.style.left=lx+'px';
  lp.style.top=ly+'px';
  lp.style.display='flex';
  lp.style.pointerEvents='all';
  lp.classList.add('visible');
  clearTimeout(lpHideTimer);
}

function hideLensPreview(){
  const lp=document.getElementById('lensPreview');
  if(lp){lp.classList.remove('visible');lp.style.display='';}
}

// ── CANVAS CLICK: show lens preview when clicking a camera placement ──────
function setupLensPreviewHover(cvs,sk){
  // Now click-based, not hover — avoids blocking right-click delete
  cvs.addEventListener('dblclick',e=>{
    if(CS[sk].w===0||CS[sk].h===0)return;
    const r=cvs.getBoundingClientRect();
    const x=(e.clientX-r.left)*(CS[sk].w/r.width);
    const y=(e.clientY-r.top)*(CS[sk].h/r.height);
    const cam=placements.find(p=>p.product.category==='Cameras'&&Math.hypot(p.x-x,p.y-y)<22);
    if(cam){
      e.stopImmediatePropagation();
      e.preventDefault();
      showLensPreview(e.clientX,e.clientY,parseCameraSpecs(cam.product));
    }
  });
}

