// Prevent hiding when hovering the preview itself
// Close preview when clicking anywhere outside it
document.addEventListener('click',e=>{
  const lp=document.getElementById('lensPreview');
  if(lp&&lp.style.display==='flex'&&!lp.contains(e.target)){
    hideLensPreview();
  }
});
document.addEventListener('keydown',e=>{
  if(e.key==='Escape'){hideLensPreview();closeLensExpand(null,true);}
});

